public void createInventQualityOrderLines()
{
    InventQualityOrderLineResults   inventQualityOrderLineResults;
    InventQualityOrderTable         inventQualityOrderTable;

    next createInventQualityOrderLines();

    inventQualityOrderTable = InventQualityOrderTable::find(this.QualityOrderId);

    if (this.TestGroupId)
    {
        utcdatetime currentTime = DateTimeUtil::getSystemDateTime();
        this.KPMGCommon_UpdateInventQualityOrderLinesFromTestGroupMember(currentTime);
    }

    ttsbegin;
    while select forupdate inventQualityOrderLineResults
        where inventQualityOrderLineResults.QualityOrderId == this.QualityOrderId
           && !inventQualityOrderLineResults.TestResultQuantity
           && !inventQualityOrderLineResults.PdsCWTestResultQuantity
    {
        inventQualityOrderLineResults.TestResultQuantity        = inventQualityOrderTable.Qty;
        inventQualityOrderLineResults.PdsCWTestResultQuantity   = inventQualityOrderTable.PdsCWQty;
        inventQualityOrderLineResults.update();       
    }
    ttscommit;
}

protected void KPMGCommon_UpdateInventQualityOrderLinesFromTestGroupMember(utcdatetime _currentTime)
{
    InventQualityOrderLine          inventQualityOrderLine;
    InventTestGroupMember           inventTestGroupMember;
    InventQualityOrderId            inventQualityOrderId    = this.QualityOrderId;

    update_recordset inventQualityOrderLine 
        setting
            KPMGCommon_CertOfAnalysisTestUnit = inventTestGroupMember.KPMGCommon_CertOfAnalysisTestUnit,
            KPMGCommon_CertOfAnalysisTestLimitValue = inventTestGroupMember.KPMGCommon_CertOfAnalysisTestLimitValue
        //order by QualityOrderId, TestSequence
        where inventQualityOrderLine.QualityOrderId == inventQualityOrderId
        join inventTestGroupMember
          where inventTestGroupMember.TestGroupId       == this.TestGroupId
             && inventTestGroupMember.TestId            == inventQualityOrderLine.TestId
             && inventTestGroupMember.ValidFromDateTime <= _currentTime
             && inventTestGroupMember.ValidToDateTime   >  _currentTime;

    /*
