    while select forupdate inventQualityOrderLine
        order by QualityOrderId, TestSequence
        where inventQualityOrderLine.QualityOrderId == inventQualityOrderId
        join inventTestGroupMember
            where inventTestGroupMember.TestGroupId       == this.TestGroupId
               && inventTestGroupMember.TestId            == inventQualityOrderLine.TestId
               && inventTestGroupMember.ValidFromDateTime <= _currentTime
               && inventTestGroupMember.ValidToDateTime   >  _currentTime
    {
        inventQualityOrderLine.KPMGCommon_CertOfAnalysisTestUnit = inventTestGroupMember.KPMGCommon_CertOfAnalysisTestUnit;
        inventQualityOrderLine.KPMGCommon_CertOfAnalysisTestLimitValue = inventTestGroupMember.KPMGCommon_CertOfAnalysisTestLimitValue;
        inventQualityOrderLine.doUpdate();
    }
    ttscommit;
    */
}
